package com.areva.engineering.actions;

import javax.servlet.http.*;
import org.apache.struts.action.*;

public class CircuitPlanRoutingAction extends Action {
    @Override
    public ActionForward execute(ActionMapping mapping, ActionForm form, 
                                 HttpServletRequest request, HttpServletResponse response) throws Exception {

        // Cast des eingehenden Struts-Formulars
        DynaActionForm planForm = (DynaActionForm) form;
        String circuitId = planForm.getString("circuitId");

        // Validierung und Datenbank-Interaktion via SQL
        if (circuitId == null || circuitId.trim().isEmpty()) {
            return mapping.findForward("error");
        }

        // Logik zur Speicherung im Ingres-System über ein DAO (vereinfacht)
        request.setAttribute("statusMessage", "Stromlaufplan erfolgreich aktualisiert.");
        return mapping.findForward("success");
    }
}

// Java Servlet zur dynamischen XML/XSLT-Transformation für mobile Clients
public class XSLTTransformerServlet extends HttpServlet {

    protected void doGet(HttpServletRequest request, HttpServletResponse response) 
            throws ServletException, IOException {

        response.setContentType("text/html; charset=UTF-8");
        PrintWriter out = response.getWriter();

        try {
            Source xmlSource = new StreamSource(getServletContext().getResourceAsStream("/WEB-INF/content.xml"));
            Source xslSource = new StreamSource(getServletContext().getResourceAsStream("/WEB-INF/pda-format.xsl"));

            TransformerFactory factory = TransformerFactory.newInstance();
            Transformer transformer = factory.newTransformer(xslSource);

            // Dynamische Usability-Anpassung (z.B. Schriftgröße/Sprache)
            transformer.setParameter("uiMode", "pda-compact");

            transformer.transform(xmlSource, new StreamResult(out));
        } catch (TransformerException e) {
            throw new ServletException("XSLT Transformation failed", e);
        }
    }
}
